<template>
    <div class="evan" >
        <div class="back"></div>
        <h1 class="back-title">EL EVANGELIO DE JESUS</h1>
        <div class="main" >
            <div class="section" >
                <div>
                    <h3>Muerte</h3>
                    <img class="image" src="../assets/jesus-cross.png" alt="">
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
             <div class="section rock" >
                <div>
                    <h3>Sepultura</h3>
                    <img class="image" src="../assets/rock.png" alt=""  style="top: 50px; position:relative">
                    <p  style="top: 70px; position:relative"> Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
             <div class="section" >
                <div>
                    <h3>Resurrecion</h3>
                    <img class="image" src="../assets/jesus.png" alt="">
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
        </div>

    </div>
</template>

<script>
import $ from 'jquery'

export default {

   mounted(){
       $('.section').click(function(){
           $(this).toggleClass('show-text')
       })
   }

}
</script>

<style lang="scss" scoped>
    .evan {
        position: relative;
        height: 100vh;
        width: 100%;
        z-index: 1;
        overflow: hidden;
        background: rgba(85, 255, 238, 0.322);
        
    }
    .back {
        height: 100vh;
        width: 100%;
        background-image: url("../assets/cloud.png");
        background-attachment : fixed;
        background-size: cover;
        // background: rgba(85, 255, 238, 0.322);
        opacity: .5;
        top: 0;
        z-index: 1;
        position: absolute;

    }
    .back-title{
        position: absolute;
        font-weight: 500;
        color: black;
        z-index: 3;
        font-size: 11vmin;
        top: 15%;
        left: 50%;
        opacity: .1;
        margin-right: -50%;
        transform: translate(-50%, -50%)
       
    }
    .main {
    
    width: 100%;
    height: 100%;
    // background: rgb(102, 101, 101);
        .section {
            z-index: 3;
            position: relative;
            float: left;
            width: 33.33%;
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
            transition: all .4s ease;
            div {
                width: 100%;
                height: 50%;
                padding: 80px;
                padding-top: 20%;
                position: relative;
                text-align: center;
                color: rgb(255, 255, 255);
                cursor: pointer;
            }
            img {
            position: relative;
            transition: all .4s ease;
            transform: translateY(0px);
            // filter: grayscale(1) brightness(.6) 

            }
            h3 {
                font-size: 50px;
                color:white;
                opacity:0;
            transition: all .4s ease;
                
            }
            p {
                opacity: 0;
                transition: all .4s ease;
                transform: translateY(50px);
            }
        &:hover {
            background: rgba(0, 0, 0, 0.7)!important;
            transition: all .5s ease;

            img {
                transform: scale(1.2)  translateY(0px);
                transition: all .4s ease;
                filter: grayscale(1) brightness(.8) 

            }
            h3 {
                opacity: 1;
            }
        }
        }
        
    }

    .show-text{
        div {
            img {
                opacity: 0;
                transform: translateY(200px)!important;
            }
            p {
                opacity: 1!important;
                transform: translateY(-200px)!important;

            }

        }
   
    }
</style>



