import firebase from 'firebase'
import {realDB} from  '../../firebase/firebase'
import {s3} from  '../../aws/aws-audio';

export default { 
    store: {
        series:[]

    },
    mutations: {
        setSeries(state, payload){
            state.series = payload
        }
    },
    actions: {
        snackBarAudio({commit},payload){
            console.log(payload.class)
            $(payload.class).addClass('show');
            setTimeout(function(){ $(payload.class).removeClass('show')}, payload.timeout);
          },
        getAudioData({commit}){
            var audio = [];
            realDB.ref('series').once(('value'), function(snapshot){
                    snapshot.forEach(function(child){
                            audio.push(child.val())
                        })
                })
            .then(() => {

              commit('setSeries', audio)

            })
            .catch(
              (error) => {
                console.log(error)
                // commit('setLoading', false)
              }
            )
        },
        createSeries({commit, dispatch}, payload){
            console.log(payload)
                
            var newSeriesName = payload.series.series_name.replace(/ /g, "-")
            var newimageName = payload.image.replace(/ /g, "-")
            
            realDB.ref("series").child(newSeriesName).set({
                    series_name : newSeriesName,
                    series_img: "https://s3.us-east-2.amazonaws.com/idcaudio/" + newSeriesName + '/' + newimageName,
                    isActive: false,
                    series_des: payload.series.series_des,
                    data: [{name: "fill"}]
                })

            
            var SeriesKey = encodeURIComponent(newSeriesName) + '/';
                s3.putObject({Key: SeriesKey}, function(err, data) {
            
                });
            
                var albumPhotosKey = encodeURIComponent(newSeriesName) + '/';
            
            let extn = newimageName.split('.').pop();

            var contentType;

                if (extn == 'png' || extn == 'jpg' || extn == 'gif') contentType = "image/" + extn;

                var photoKey = albumPhotosKey + newimageName;
                s3.upload({
                    Key: photoKey,
                    Body: payload.imageFile,
                    ContentType: contentType,
                    ACL: 'public-read'
                }, function(err, data) {
                    if (err) {
                    return alert('There was an error uploading your photo: ', err.message);
                    }
                }).on('httpUploadProgress', function(e) {

                           dispatch('snackBarAudio', {timeout:3000, class: '.jump'})
                       
                   });
                   
            dispatch('getAudioData')            
        },
        audioUpload({commit, dispatch}, payload){

            console.log(payload)

            var folderSeriesKey = encodeURIComponent(payload.folderName) + '/';

            var sizeTotal = 0;
            var loaded = [];
            var newFilesName = [];

            for (var i = 0; i < payload.files.length; i++) {
                sizeTotal += payload.files[i].size;
                loaded[payload.files[i].name] = 0;
                newFilesName.push(payload.files[i].name);

            }

            for(var i= 0; i < payload.files.length; i++){
    
                realDB.ref("series").child(payload.folderName).child('audio').push().set({
                      name: payload.files[i].name,
                      url: folderSeriesKey + payload.files[i].name,
                      seriesImg: payload.seriesImg
              })
                                
          s3.upload({
              Key: folderSeriesKey + payload.files[i].name,
              Body: payload.files[i],
              ContentType: "audio/*",
              ACL: 'public-read'
          }, 
          function(err, data) {
              if (err) {
                  console.log(err)
              return alert('There was an error uploading your photo: ', err.message);
              }
          }).on('httpUploadProgress', function(e) {

           loaded[this.body.name] = e.loaded;
              var loadedTotal = 0;
              for (var j in loaded) {
                  loadedTotal += loaded[j];
              }

              var progress = Math.round(loadedTotal / sizeTotal * 100);
              document.getElementById("bar").style.width = progress + '%'
              document.getElementById("perc").innerHTML = progress + '%';
             
              if (loadedTotal === sizeTotal) {
                  console.log("upload successful!")
                  dispatch('snackBarAudio', {timeout:3000, class: '.files'})
              }
          });
          
        }  


        }

    },
    getters: {

    }

}


