<template>
<div class="study">
    <div class="intro">
        <h1 class="fade-in">{{title.replace(/-/g, " ")}}</h1>
        <p class="fade-in-o">{{seriesAll[3]}}</p>
        <img v-parallax.modifier="0.3" :src="seriesAll[4]" alt="">
        <div class="tab">
            <h2>Serie | {{title.replace(/-/g, " ")}}</h2>
            <h2>Sermones | {{series.length}}</h2>
        </div>
    </div>
    <div class="search">
            <i class="fa fa-search"></i>
            <input class="bar" type="text" v-model="search" name="search">
    </div>
    <div class="series">
    <!-- <div class="overlay"></div> -->
            <div>
               <li class="item" v-for="(audio, index) in searchList" :key="index" :id="audio.url" :value="audio.url"  > 
                    <div class="sub">
                        <h2 class="truncate para">{{audio.name.replace(/.mp3/g, "")}}</h2>
                        <p>Ricardo Barrera | DATE</p>
                    </div>
                    <div class="icon">
                            <i v-show="!pause" class="fa fa-play" ></i>
                            <i v-show="pause" class="fa fa-pause" ></i>
                            <i class="fa fa-cloud-download" style="padding: 10px 10px;"></i>
                            <i class="fa fa-share-alt"></i>
                    </div>
                </li> 
            </div>
        </div>

        <div class="controls">
            <!-- <img src="../assets/overlay.png" alt="">              -->
           <!-- <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" @input="seeking"></div>  -->
            <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" ></div>
            <div class="main">
                <i class="fa fa-backward" aria-hidden="true"></i>
                <i class="fa fa-play" aria-hidden="true"></i>
                <i class="fa fa-pause" v-if="pause" aria-hidden="true"></i>
                <i class="fa fa-forward" aria-hidden="true"></i>
            </div>
        </div>
        <div class="foot">
            <foot/>
        </div>
</div>
</template>

<script>
import $ from 'jquery'
import axios from 'axios'
import firebase from 'firebase'
import {realDB} from  '../firebase/firebase'
import {s3} from  '../aws/aws-audio';
import foot from './Footer.vue'

export default {
    data(){
        return {
            pause: false,
            series:[],
            seriesAll: [],
            search: '',
            title: '',
            des: ''
        }
    }, 
    components:{
    foot
},
    methods: {
        toggleOff(serie){
                serie.isActive = false;
            },

        toggleCardOn(serie){
            this.currentSerieSel = [];
            serie.isActive = true;

            for (var audio in serie.audio) {
                    this.currentSerieSel.push(serie.audio[audio])
                    }

        

        },
    },
        computed:{
            // series(){
            //     return this.$store.state.audio.series
            // },
            searchList: function(){
                return this.series.filter((serie) => {
                    return serie.name.toLowerCase().match(this.search);
                })
            },
            sortList: function(){
                var audio = this.currentSerieSel;

                return audio.sort(function(a, b){
                        if(a.name < b.name) return -1;
                        if(a.name > b.name) return 1;
                        return 0;
            })
            },
        },
    created(){

        //    this.series2 = null;

          var arr = [];
          this.title = this.$route.params.serie;

            realDB.ref('series').child(this.$route.params.serie).on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                    arr.push(child.val())
                })
               
            })

            // this.des = arr[3]

          this.seriesAll = arr
          console.log(this.seriesAll)
            for(var prop in arr[0]){

                this.series.push(arr[0][prop])
            }
      
        
    //   this.$store.dispatch('getAudioData')
    },  
    mounted(){
    $('.fa-search').click(function(){
        $('.search').toggleClass('show');
    })
}

}
</script>

<style scoped lang="scss">

.study {
    background: #fff;
    // height: 100%;
    position: relative;
    z-index: 1;
}

.search {
    height: 70px;
     input {
            position: relative;
            opacity: 0;
            font-size: 25px;
            // color: white;
            font-family: 'Montserrat', sans-serif;
            font-weight: 200;
            top: 10px;
            left:40px;
            width: 93%;
            background: transparent;
            border: none;
            border-bottom: solid #8cdacf 2px;
            transition: all .3s ease-in-out;
            
        }
        input[type=text] {
            color: rgb(78, 138, 143);
            font-weight: 500;
        }
          i {
                top: 10px;
                color: #4f4f4f;
                font-size: 40px;
                position: relative;
                left: 50%;
                z-index: 3;
                transition: all .5s ease-in-out;
                cursor: pointer;
                
        }
}
 .show {
     input {
         opacity: 1;
         transition-delay: .4s;
     }
     i {
         left: 30px;
     }
 }       
 .tab {
     display: inline-flex;
     h2 {
         position: relative!important;
         width: 200px;
     }
 }

.series {
        margin: 0!important;
        padding: 0!important;
        padding-bottom: 30px!important;
        height: auto;
        position: relative;
        z-index: 9;
    div {
        height: 100%;
        width: 100%;
        position: relative;
        background: white;
       
        li {
        list-style: none;
        position: relative;
        height: 80px;
        background: white;
        width: 100%;
        cursor: pointer;

        
         h2 {
            position: absolute;
            z-index: 2;
            color: #222;
            border-bottom: #d3d0d0 solid 1px;
            left: 20px;
            padding-bottom: 50px;
            font-weight: 600;
            font-size: 1.5vmax;
            width: 98%;
         }
         p {
            top: 70px;
            z-index: 7;
            left: 40px;
            font-style: italic;
            position: relative;
         }
      
        }
    }
        
}
.sub {
    // width: 50%;
    position: relative;
}

  .icon {
            position: absolute;
            left: 75%;
            top: -45px;
            background: transparent!important;
         i {
             margin-left: 40px;
             border: solid #222 2px;
             opacity: .6;
            //  margin: 10px;
             position: relative;
             padding: 10px 12px;
             font-size: 25px;
             border-radius: 50%;
         }
         }

.controls {
    position: fixed;
    background: rgba(34, 34, 34, 0.836);
    left:-0px;
    bottom: 0;
    z-index: 999;
    width: 100%;
    height: 80px;
    .main {
         position: relative;
            display: flex;
            justify-content: center;
            align-content: center;
            top:15px;
    }
            i {
            top: -30px;
            float: left;
            position: relative;
            display: flex;
            justify-content: center;
            align-content: center;
            margin: 15px;
            padding: 5px;
            color: #8cdacf;
            font-size: 40px;
            cursor: pointer;
        }
    .seek {
        // position: absolute;
        z-index: 9;
        top:-10px;
        
        input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: rgba(0, 0, 0, 0.637);
                color:white;
                border:none;
                height:13px;
                width: 100%;
            }    
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: #528b84;
                height:20px;
                width:7px;
                // top: -3px;
                position: relative;
                // border: solid #222 2px;
                border-radius:5px;
                cursor:pointer;
            }
            input[type=range]::-webkit-slider-runnable-track {
              cursor: pointer;                
              background: transparent;
                border-radius: 1px;
                border: none;
                }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
            }
        
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:50px;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
 
                width:11px;
                cursor:pointer;                
                border-radius:50px;

            }
    }
}
.foot { background: black;}

@media screen and (max-width: 748px) {
    .intro {

    img {opacity: .6; height: 100%; width: auto; top: 0px;}
    .tab {
        width: 100%;
        height: 40px;
        h2 {
            font-size: 10px;
            color:#87d1c8;
            margin-left: 10px;
        }
    }
}

.search {
    height: 20px;
     input {
            position: relative;
            opacity: 1;
            font-size: 16px;
            top: -20px;
            left:25px;
            width: 80%;
           
            
        }
  
          i {
                top: -20px; 
                font-size: 30px; 
                left: 20px;
                
        }
}

.series {
    position: relative;
    overflow-x: hidden;
    height: 100vh;
    div {
        height: 100px;
        width: auto;
        position: relative;
        background: white;
       
        li {
        
         h2 {
            left: 20px;
            font-size: 1.2vmax;
         }
         p {
            top:30px;
            font-size: 8px;
         }
      
        }
    }
        
}
 .icon {
            position: absolute;
            left: 50%;
            top: -75px;
            width: 10px;
         i {
             margin-left: 10px;
             border: solid #222 2px;
             opacity: .6;
            //  margin: 10px;
             position: relative;
             padding: 10px 12px;
             font-size: 10px;
             border-radius: 50%;
         }
         }
  
}
</style>



