 <template>
    <div class="wel" style="overflow:hidden;">
        <div class="back"></div>
        <div class="rec1">

        </div>
        <div class="rec2"></div>
        <div class="rec3"></div>
        <div class="rec4"></div>
        <div class="rec5"></div>

        <div class="main">
            <div class="section col">
            <img class="overlay" src="../assets/overlay.png" alt="">
                <div>
                    <div class="icons"><i class="fa fa-handshake-o"></i></div>
                    <h3>Bienvenido</h3>
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
            <div class="section col">
            <img class="overlay" src="../assets/overlay.png" alt="">
                <div >
                    <div class="icons"><i class="fa fa-users" aria-hidden="true"></i></div>
                    <h3>Acerca</h3>
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
            <div class="section col">
            <img class="overlay" src="../assets/overlay.png" alt="">
                
                <div>
                    <div class="icons"><i class="fa fa-globe" aria-hidden="true"></i></div>
                    <h3>Mission</h3>
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
            <div class="section col">
            <img class="overlay" src="../assets/overlay.png" alt="">
                <div>
                    <div class="icons"><i class="fa fa-book" aria-hidden="true"></i></div>
                    <h3>Ensenansa</h3>
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
            <div class="section col">
            <img class="overlay" src="../assets/overlay.png" alt="">
                
                <div style="background: rgba(102, 201, 199,.0)">
                    <div class="icons"><i class="fa fa-heart" aria-hidden="true"></i></div>
                    <h3>Edificacion</h3>
                    <p>Lorem ipsum, dolor sit amet consectetur adipisicing elit. Fugit laudantium cupiditate suscipit veniam, dolorem delectus vel velit. Fugiat labore, magni harum mollitia sunt ipsam ratione suscipit id, veritatis impedit esse?</p>
                </div>
            </div>
        </div>
        
    </div>
</template>

<script>
import $ from 'jquery'

export default {
mounted(){
    $('.col').hover(function(){
        $(this).children().toggleClass('show')
    })
}
}
</script>

<style lang="scss" scoped>
.wel {
    // z-index: 1;
    position: relative;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    display: flex;
    justify-content: center;
     align-items: center;
    //  background: rgb(0, 0, 0);
     .back {
        position: absolute;
        height: 100%;
        width: 100%;
        background: url("../assets/path.jpg");
        background-size: 100% 100%;
        opacity: .6;
        // filter: contrast(3);
     }
     .rec1, .rec2, .rec3, .rec4, .rec5 {

         background: rgba(57, 105, 107, .2);
         height: 100%;
         width: 2500px;
         top: 0%;
         position: absolute;
            overflow: hidden;
         z-index: 1;
     }
        .rec1 {
         left: 0%;
     }
        .rec2 {
         left: 26%;
     }
     .rec3 {
         left: 42%;
     }
       .rec4 {
         left: 58%;
         
     }
         .rec5 {
         left: 74%;
         
     }
        img {
            opacity: 0;
            position: absolute;
            top: -20%;
            width:100%;
            z-index: 1;
            height: 150%;
            left: 0;
            transition: all .4s ease-in-out;
        }
        .show {
            opacity: .9;
        }
    .main {
    width: 80%;
    height: 80%;
    // background: white;
        .section {
            z-index: 6;
            position: relative;
            float: left;
            width: 20%;
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
            div {
                width: 100%;
                height: 50%;
                padding: 50px;
                position: relative;
                z-index: 2;
                .icons {
                    left: -50px;
                    position: absolute;
                    display: flex;
                    justify-content: center;
                    align-items: center;
                    opacity: 1;
                    z-index: 2;
                    transition: all .5s ease;

                    i {
                        color:rgb(130, 160, 161);
                        color:white;
                        font-size: 100px;
                    }
                  
                }
                  &:hover {
                        h3, p {
                            transform: translateY(0px);
                            opacity: 1;
                            transition: all .5s ease;
                        }
                        .icons {
                            transform: translateY(-300px);
                            opacity: 0;
                            transition: all .5s ease;

                        }
                    }
                
               

                h3{
                    position: relative;
                opacity: 0;
                z-index: 0;
                display: flex;
                justify-content: center;
                align-items: center;
                    color:white;
                    margin-top: 60px;
                    font-size: 35px;
                    transform: translateY(200px);
                    transition: all .5s ease;
                }
                p {
                    position: relative;
                    z-index: 0;
                    opacity: 0;
                    color:white;
                    font-size: 20px;
                    transform: translateY(200px);
                    transition: all .5s ease;
                }
                
            }
        }
    }
}
 
</style>



