<template>
<div>
 <div id="gallery">
        <div class="wrapper"> 
            <div class="masonry">
                    <div v-for="(image, index) in output" :key="index" class="item"  >
                            <div class="img-cont" data-aos="fade-up" data-aos-anchor-placement="top-center" data-aos-duration="1000">
                                <img :src="image.url" alt="" class="v-img"> 
                            </div>
                            <div class="img-text" data-aos="fade-right" data-aos-anchor-placement="top-bottom" data-aos-duration="1000">{{image.text}}</div>
                    </div>   
            </div>
         </div>

 </div>
 </div>
</template>

<script>
// import Loader from "../components/main/Loader.vue";
import axios from 'axios';

export default {
  components:{
    //   "loader": Loader,
  },
  data(){
      return {
          loading: true,
          gallery_images: "",
          showingModal: false,
          imageClicked: '',
          photoURL: {},
          output: {},

            show   : false, // display content after API request
            offset : 5,     // items to display after scroll
            display: 5,     // initial items
            trigger: 300,   // how far from the bottom to trigger infinite scroll
            end    : false, // no more resources

      }
  },
  methods: {
      instaData: function(){

          var access_token = "efadf64726bd76295377877a5689a6dc";

                axios.get("https://api.flickr.com/services/rest/?&method=flickr.people.getPhotos&api_key="+ access_token +"&user_id=139127837@N05&extras=description&per_page=100&format=json&jsoncallback=?")
                    .then(response => {

                        var result = response.data.replace("jsonFlickrApi(", "").replace(')','');
                        var data = JSON.parse(result);
                        var photo = data.photos.photo;
                        var arr = [];
                        
                        for (var i = 0 ; i < photo.length; i++ ) {
                            var temp = {};
                            
                            temp['url'] = 'http://farm' + photo[i].farm + '.static.flickr.com/' + photo[i].server + '/' + photo[i].id + '_' + photo[i].secret + '_b.jpg';
                            temp['text'] = photo[i].title;
                            temp['des'] = photo[i].description._content;

                             arr.push(temp);
                        }

                        this.output = arr;
                        console.log(this.output)

                        setTimeout(() => {
                            this.loading = false;
                        }, 1000);


                    });

      },

      clickedImage(image){

          this.imageClicked = image;
      }
},
mounted(){
    this.instaData();
   
}
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

// @import '../assets/css/main';

   #gallery {
        height: 100%;
        position: relative;
        background: white;
        // top: -60px;
        .wrapper {
            position: relative;
            margin-bottom: 50px;

        }

.masonry {
    position: relative;
    // padding: 0;
    width: 90%;
    left: 5%;
    -moz-column-gap: 1.5em;
    -webkit-column-gap: 1.5em;
    column-gap: 20px;
    font-size: .85em;

}

.item {
    display: inline-block;
    position: relative;
    z-index: 1;
    margin-top: 20px;
        //  background: rgba(34, 34, 34, 0.576);
    

}

.img-text {
    position: absolute;
    bottom: 6%;
    color:white;
    left: 5%;
    font-size: 40px;
    // text-align: center;
    width: 100%;
    font-weight: 400;
    // font-family: brush;

}   
.img-cont {
    overflow: hidden;
            .v-img {
            max-height: 100%;
            max-width: 100%;
            filter: brightness(.6);
            transition: all .5s;
            // opacity: .8;
            cursor: pointer;
            z-index: 0;
            
        }
        .v-img:hover {
             filter: brightness(1);
             transition: all .5s ease-in-out;

        }
}


@media only screen and (min-width: 300px) {
    .masonry {
        -moz-column-count: 1;
        -webkit-column-count: 1;
        column-count: 1;
    }
}

@media only screen and (min-width: 700px) {
    .masonry {
        -moz-column-count: 3;
        -webkit-column-count: 3;
        column-count: 3;
    }
}

@media only screen and (min-width: 900px) {
    .masonry {
        -moz-column-count: 4;
        -webkit-column-count: 4;
        column-count: 4;
    }
}

@media only screen and (min-width: 1024px) {
    .masonry {
        -moz-column-count: 4;
        -webkit-column-count: 4;
        column-count: 3;
    }
}



    }

    @media only screen and (max-width: 800px) {
        
   #gallery {
        height: 100%;
        position: relative;
        background: white;
        // top: -60px;
        .wrapper {
            position: relative;
            margin-bottom: 50px;

        }

.masonry {
    position: relative;
    // padding: 0;
    width: 90%;
    left: 5%;
    -moz-column-gap: 1.5em;
    -webkit-column-gap: 1.5em;
    column-gap: 20px;
    font-size: .85em;

}

.item {
    display: inline-block;
    position: relative;
    z-index: 1;
    margin-top: 20px;
        //  background: rgba(34, 34, 34, 0.576);
    

}

.img-text {
    position: absolute;
    bottom: 6%;
    color:white;
    left: 0%;
    font-size: 20px;
    background: rgba(0, 0, 0, 0.548);
    // text-align: center;
    width: auto;
    padding: 5px;
    font-weight: 400;
    // font-family: brush;

}   
.img-cont {
    overflow: hidden;
            .v-img {
            max-height: 100%;
            max-width: 100%;
            filter: brightness(1);
            transition: all .5s;
            // opacity: .8;
            cursor: pointer;
            z-index: 0;
            
        }
        .v-img:hover {
             filter: brightness(1);
             transition: all .5s ease-in-out;

        }
}
     }

    }
    

</style>



